export function convertImageModelFileToDataUri(file: ImageModelV3File): string {
  if (file.type === 'url') return file.url;

  return `data:${file.mediaType};base64,${
    typeof file.data === 'string'
      ? file.data
      : convertUint8ArrayToBase64(file.data)
  }`;
}
