// Response schema
const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(z.object({
    images: z.array(z.object({ url: z.string() })),
  })),
);

// Error schema (plain Zod, not wrapped in zodSchema — matches luma pattern for error schemas)
const pixelArtErrorSchema = z.object({ error: z.string() });
export type PixelArtErrorData = z.infer<typeof pixelArtErrorSchema>;

// Provider options schema
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),
      pixelDensity: z.number().nullish(),
    }).passthrough(),
  ),
);
export type PixelArtImageModelOptions = InferSchema<typeof pixelArtImageModelOptionsSchema>;
```

**Error handler** (module-level function):
```typescript
function createPixelArtErrorHandler() {
  return createJsonErrorResponseHandler({
    errorSchema: pixelArtErrorSchema,
    errorToMessage: (error: PixelArtErrorData) => error.error ?? 'Unknown error',
  });
}
```

#### `packages/pixel-art/src/pixel-art-provider.ts`

**Imports**: `ImageModelV3`, `NoSuchModelError`, `ProviderV3` from `@ai-sdk/provider`; `FetchFunction`, `loadApiKey`, `withoutTrailingSlash`, `withUserAgentSuffix` from `@ai-sdk/provider-utils`; `PixelArtImageModel`, `PixelArtImageModelId`, `VERSION`

```typescript
const DEFAULT_BASE_URL = 'https://api.pixelart.ai/v1';

export interface PixelArtProviderSettings {
  apiKey?: string;      // fallback: PIXELART_API_KEY env var
  baseURL?: string;     // fallback: DEFAULT_BASE_URL
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? DEFAULT_BASE_URL);
  const getHeaders = () => withUserAgentSuffix(
    {
      Authorization: `Bearer ${loadApiKey({ apiKey: options.apiKey, environmentVariableName: 'PIXELART_API_KEY', description: 'PixelArt' })}`,
      ...options.headers,
    },
    `ai-sdk/pixel-art/${VERSION}`,
  );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, { provider: 'pixel-art.image', baseURL: baseURL ?? DEFAULT_BASE_URL, headers: getHeaders, fetch: options.fetch });

  const throwNotSupported = (modelId: string, modelType: string) => { throw new NoSuchModelError({ modelId, modelType }); };

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId) => throwNotSupported(modelId, 'languageModel'),
    embeddingModel: (modelId) => throwNotSupported(modelId, 'embeddingModel'),
  };
}

export const pixelArt = createPixelArt();
```

