export type PixelArtImageModelId = 'pixel-art-v1' | 'pixel-art-v2' | (string & {});

/**
 * The visual style applied to the generated pixel-art image.
 *
 * - `pixel`: Classic pixel-art look with sharp edges and limited palette.
 * - `retro`: Retro-gaming aesthetic inspired by 16-bit era visuals.
 * - `8bit`: Pure 8-bit style reminiscent of early home computers and consoles.
 */
export type PixelArtStyle = 'pixel' | 'retro' | '8bit';

/**
 * Provider-specific settings for PixelArt image generation.
 *
 * Pass these inside `providerOptions['pixel-art']` when calling `generateImage`.
 *
 * @example
 * ```ts
 * generateImage({
 *   model: pixelArt('pixel-art-v1'),
 *   prompt: 'A dragon breathing fire',
 *   providerOptions: {
 *     'pixel-art': {
 *       style: '8bit',
 *       pixelDensity: 64,
 *     },
 *   },
 * });
 * ```
 */
export interface PixelArtImageSettings {
  /**
   * The visual style to apply to the generated image.
   *
   * - `pixel`: Classic pixel-art look with sharp edges and limited palette.
   * - `retro`: Retro-gaming aesthetic inspired by 16-bit era visuals.
   * - `8bit`: Pure 8-bit style reminiscent of early home computers and consoles.
   *
   * Forwarded to the API as `style`.
   */
  style?: PixelArtStyle;

  /**
   * The pixel density (pixels per unit) of the generated image.
   *
   * Higher values produce finer pixel grids; lower values produce blockier art.
   * Forwarded to the API as `pixel_density`.
   */
  pixelDensity?: number;
}

