import {
  ImageModelV3,
  SharedV3Warning,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  InferSchema,
  combineHeaders,
  createBinaryResponseHandler,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  createStatusCodeErrorResponseHandler,
  getFromApi,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'This model does not support the `aspectRatio` option. Use `size` to control image dimensions.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'image',
        details:
          'This model does not support image editing. Only text-to-image generation is supported.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details:
          'This model does not support mask-based image editing.',
      });
    }

    // Parse and validate provider options
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixel-art',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const { style, pixelDensity } = pixelArtOptions ?? {};

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        prompt,
        ...(n != null ? { n } : {}),
        ...(size != null ? { size } : {}),
        ...(seed != null ? { seed } : {}),
        ...(style != null ? { style } : {}),
        ...(pixelDensity != null ? { pixel_density: pixelDensity } : {}),
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: error => error.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtGenerationResponseSchema,
      ),
    });

    const downloadedImages = await Promise.all(
      response.images.map(({ url }) => this.downloadImage(url, abortSignal)),
    );

    return {
      images: downloadedImages,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }

  private async downloadImage(
    url: string,
    abortSignal: AbortSignal | undefined,
  ): Promise<Uint8Array> {
    const { value: data } = await getFromApi({
      url,
      // No auth headers needed — the URL is a pre-signed image link.
      abortSignal,
      failedResponseHandler: createStatusCodeErrorResponseHandler(),
      successfulResponseHandler: createBinaryResponseHandler(),
      fetch: this.config.fetch,
    });
    return data;
  }
}

// Response schema — kept minimal to limit breakage when the API evolves.
const pixelArtGenerationResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      images: z.array(
        z.object({
          url: z.string(), // URL of the generated image
        }),
      ),
    }),
  ),
);

const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    code: z.string().nullish(),
  }),
});

export type PixelArtErrorData = z.infer<typeof pixelArtErrorSchema>;

/**
 * Provider options schema for PixelArt image generation.
 *
 * @see https://api.pixelart.ai/v1/docs
 */
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z
      .object({
        /**
         * The visual style to apply to the generated image.
         * - `pixel`: Classic pixel-art look.
         * - `retro`: Retro-gaming aesthetic.
         * - `8bit`: Pure 8-bit style.
         *
         * Forwarded to the API as `style`.
         */
        style: z.enum(['pixel', 'retro', '8bit']).nullish(),

        /**
         * The pixel density (pixels per unit) of the generated image.
         * Forwarded to the API as `pixel_density`.
         */
        pixelDensity: z.number().positive().nullish(),
      })
      .passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

