import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixel-art-image-model';

const prompt = 'A retro space invader';

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixel-art-v1', {
    provider: 'pixel-art.image',
    baseURL: 'https://api.example.com',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/images/generate': {
      response: {
        type: 'json-value',
        body: {
          images: [{ url: 'https://api.example.com/image.png' }],
        },
      },
    },
    'https://api.example.com/image.png': {
      response: {
        type: 'binary',
        body: Buffer.from('test-binary-content'),
      },
    },
    'https://api.example.com/image1.png': {
      response: {
        type: 'binary',
        body: Buffer.from('test-binary-content-1'),
      },
    },
    'https://api.example.com/image2.png': {
      response: {
        type: 'binary',
        body: Buffer.from('test-binary-content-2'),
      },
    },
  });

  describe('doGenerate', () => {
    it('should POST to the correct URL', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(server.calls[0].requestMethod).toBe('POST');
      expect(server.calls[0].requestUrl).toBe(
        'https://api.example.com/images/generate',
      );
    });

    it('should include prompt in the request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        prompt,
      });
    });

    it('should forward n, size, and seed to the request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 2,
        size: '512x512',
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 2,
        size: '512x512',
        seed: 42,
      });
    });

    it('should omit undefined optional params from request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: undefined,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toStrictEqual({ prompt });
      expect(body).not.toHaveProperty('n');
      expect(body).not.toHaveProperty('size');
      expect(body).not.toHaveProperty('seed');
    });

    it('should forward style and pixelDensity provider options', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          'pixel-art': { style: '8bit', pixelDensity: 32 },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 1,
        style: '8bit',
        pixel_density: 32,
      });
    });

    it('should forward style without pixelDensity when only style is set', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          'pixel-art': { style: 'retro' },
        },
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toMatchObject({ style: 'retro' });
      expect(body).not.toHaveProperty('pixel_density');
    });

    it('should download multiple images in parallel when n > 1', async () => {
      server.urls['https://api.example.com/images/generate'].response = {
        type: 'json-value',
        body: {
          images: [
            { url: 'https://api.example.com/image1.png' },
            { url: 'https://api.example.com/image2.png' },
          ],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 2,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(2);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
      expect(result.images[1]).toBeInstanceOf(Uint8Array);
    });

    it('should return the downloaded image as a Uint8Array', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
    });

    it('should pass custom headers', async () => {
      const model = createBasicModel({
        headers: () => ({
          Authorization: 'Bearer provider-key',
          'X-Custom-Header': 'provider-value',
        }),
      });

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: { 'X-Request-Header': 'request-value' },
        files: undefined,
        mask: undefined,
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        authorization: 'Bearer provider-key',
        'x-custom-header': 'provider-value',
        'x-request-header': 'request-value',
      });
    });

    it('should emit a warning for unsupported aspectRatio', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toContainEqual(
        expect.objectContaining({ type: 'unsupported', feature: 'aspectRatio' }),
      );
    });

    it('should emit a warning for unsupported files (image editing)', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: [{ type: 'url', url: 'https://example.com/ref.png', mediaType: 'image/png' }],
        mask: undefined,
      });

      expect(result.warnings).toContainEqual(
        expect.objectContaining({ type: 'unsupported', feature: 'image' }),
      );
    });

    it('should emit a warning for unsupported mask', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: { type: 'url', url: 'https://example.com/mask.png', mediaType: 'image/png' },
      });

      expect(result.warnings).toContainEqual(
        expect.objectContaining({ type: 'unsupported', feature: 'mask' }),
      );
    });

    it('should emit warnings for all unsupported features simultaneously', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: '1:1',
        seed: undefined,
        providerOptions: {},
        files: [{ type: 'url', url: 'https://example.com/ref.png', mediaType: 'image/png' }],
        mask: { type: 'url', url: 'https://example.com/mask.png', mediaType: 'image/png' },
      });

      const features = result.warnings.map(w => w.feature);
      expect(features).toContain('aspectRatio');
      expect(features).toContain('image');
      expect(features).toContain('mask');
    });

    it('should include correct response metadata', async () => {
      const fixedDate = new Date('2025-01-01T00:00:00Z');
      const model = createBasicModel({ currentDate: () => fixedDate });

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response.modelId).toBe('pixel-art-v1');
      expect(result.response.timestamp).toEqual(fixedDate);
    });

    it('should handle API errors', async () => {
      server.urls['https://api.example.com/images/generate'].response = {
        type: 'json-value',
        status: 400,
        body: {
          error: { message: 'Invalid prompt', code: 'invalid_prompt' },
        },
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        }),
      ).rejects.toMatchObject({
        message: 'Invalid prompt',
        statusCode: 400,
      });
    });
  });
});

